import{_ as a,o as n,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"59. Annual Leave","description":"","frontmatter":{"title":"59. Annual Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","annual-leave","hours","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/leave/59-annual-leave.md","filePath":"ebas/allied-health/leave/59-annual-leave.md"}'),l={name:"ebas/allied-health/leave/59-annual-leave.md"};function r(i,e,s,p,h,d){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_59-annual-leave" tabindex="-1">59. Annual Leave <a class="header-anchor" href="#_59-annual-leave" aria-label="Permalink to &quot;59. Annual Leave&quot;">​</a></h1><p><strong>59.1</strong> Period of leave</p><p><strong>(a)</strong> From 7 July 2022, an Employee will be entitled to 190 hours annual leave on ordinary pay per year of continuous service with the Employer.</p><p><strong>(b)</strong> Annual leave accrues progressively during a year of continuous service according to the Employee’s ordinary hours of work and accumulates from year to year.</p><p><strong>59.2</strong> Additional leave</p><p><strong>(a)</strong> Weekend worker</p><p><strong>(i)</strong> An Employee who is a Weekend Worker (as defined in subclause 58.1) who works for more than four (4) ordinary hours on 10 or more weekends per year of continuous service is entitled to an additional 38 hours’ annual leave on the same terms and conditions.</p><p><strong>(ii)</strong> The provisions of this subclause 59.2(a) have the same effect and give an Employee an entitlement to annual leave that is the same as the Employee’s entitlement under the NES relating to shiftworkers under For the purpose of the NES only a shiftworker is an Employee who is regularly rostered to work Sundays and public holidays.</p><p><strong>(iii)</strong> An Employee’s entitlement to annual leave under this subclause 59.2(a) operates in parallel with the Employee’s NES entitlement, but not so as to give the Employee a double benefit.</p><p><strong>(iv)</strong> A Weekend Worker whose employment is terminated at the end of a period of employment which is less than one (1) year from the date of commencement of the employment, or the date upon which the Employee last became entitled to annual leave, will be paid an amount equal to 1/48th of their ordinary pay in respect of that period of employment.</p><p><strong>(v)</strong> The entitlement in subclause 59.2(a) is additional to the On-Call and Rostered Overtime entitlement provided by subclause 59.2(b), but both entitlements cannot be claimed for the same bodies of work.</p><p><strong>(b)</strong> On Call and Rostered Overtime</p><p><strong>(i)</strong> An Employee who is rostered on-call or who performs rostered overtime for more than four (4) hours on 10 or more weekends per annum will be entitled to an additional 38 hours annual leave.</p><p><strong>(ii)</strong> This entitlement is in addition to the Weekend Worker entitlement provided by subclause 59.2(a), but both entitlements cannot be claimed for the same bodies of work.</p><p><strong>(iii)</strong> Leave loading does not apply to leave accrued under this subclause 59.2(b).</p><p><strong>59.3</strong> Time of taking leave</p><p><strong>(a)</strong> Annual leave will be taken for a period agreed between the Employee and the Employer. An Employee may access accrued annual leave prior to the completion of a year of service.</p><p><strong>(b)</strong> The Employer will not unreasonably refuse to agree to a request by the Employee to take paid annual leave, including a request to take single day or part day periods of annual leave.</p><p><strong>(c)</strong> Once leave has been granted by the Employer, it will only be revoked by mutual agreement, which may be at the request of the Employee, save that the Employer will not unreasonably refuse a request by an Employee to revoke the granting of leave.</p><p><strong>(d)</strong> Where an Employee applies for annual leave the Employer will respond to such an application as soon as possible, but no later than four (4) weeks after the application has been made.</p><p><strong>(e)</strong> Where it is likely the leave request will be rejected, the Employer and Employee will consult on alternative leave days within the four (4) week period in subclause 59.3(d).</p><p><strong>(f)</strong> High Demand Holiday Periods</p><p><strong>(i)</strong> The Employer will develop and publish to affected Employees (which may be a specific department or work area) requirements for a high demand holiday period. Where this occurs, the requirement must identify: A. the high demand holiday period; B. the date by which a written request for annual leave should be submitted, save that subclause 59.3(b) still applies to a request made after this date; and C. subject to subclause 59.3(d), the date by which the Employer will notify the Employee in writing that their annual leave request is approved or, if not approved, the reasons for the leave not being approved.</p><p><strong>(ii)</strong> In determining applications for high-demand periods, the Employer will consider all the circumstances including but not limited to: A. the Employer&#39;s operational needs; B. the Employee&#39;s family responsibilities; and C. whether previous annual leave applications by the Employee for the same high demand period were successful or not.</p><p>Example A department generally receives more applications for annual leave over school term breaks than it can accommodate. This means that school term breaks are ‘high demand periods’ for that department within the meaning of this sub clause 59.3(f) and the Employer must publish the information specified above at subclause 59.3(f)(i) and, when determining the applications, apply the considerations at subclause 59.3(f)(ii).</p><p><strong>59.4</strong> Leave in advance</p><p><strong>(a)</strong> The Employer may allow an Employee to take annual leave in advance of accrual.</p><p><strong>(b)</strong> Where an Employee remains in annual leave debt upon termination, such amount (including any leave loading paid) may be deducted from any amounts otherwise payable to the Employee upon termination of the employment.</p><p><strong>59.5</strong> Payment on termination If, when the employment of an Employee ends, the Employee has a period of untaken accrued annual leave (including under subclauses 59.2(a) and (b)), the Employer must pay to the Employee the amount that would have been payable to the Employee had the Employee taken that period of annual leave, including any annual leave loading.</p><p><strong>59.6</strong> Payment for Leave</p><p><strong>(a)</strong> Employees will receive their ordinary pay and any amount required by subclause 59.6(b) (Annual leave loading or penalties) for the Employee’s ordinary hours of work in the period of annual leave.</p><p><strong>(b)</strong> Annual Leave loading or penalties In addition to ordinary pay an Employee will receive the higher of:</p><p><strong>(i)</strong> leave loading of 17.5% calculated on the relevant wage rate prescribed in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a>, subject to the cap at subclause 59.6(c); or</p><p><strong>(ii)</strong> the payments listed below which the Employee would have received had the Employee not been on leave: A. shift allowances (<a href="/eba/ebas/allied-health/allowances/38-shift-work-allowance.html">clause 38</a>); and B. rates for Saturday and/or Sunday (<a href="/eba/ebas/allied-health/hours-of-work/51-rates-for-saturdays-and-sundays.html">clause 51</a>).</p><p><strong>(c)</strong> Calculating leave loading or penalties</p><p><strong>(i)</strong> Leave loading under subclause 59.6(b)(i) is payable on: A. the annual leave accrued and accumulated under subclause 59.1; and B. the Employee’s weekly ordinary pay during periods of annual leave, subject to the cap (as defined in subclause 59.6(c)(ii)).</p><p><strong>(ii)</strong> The cap under subclause 59.6(c)(i)B above is the weekly rate prescribed by this Agreement for AHP1 Grade 3, Year 1.</p><p><strong>(iii)</strong> To determine which payments the Employee would have received had the Employee not been on leave for the purpose of subclause 59.6(b)(ii), this will be done either by using: A. the projected roster, being the roster the Employee would have worked had they not been on leave; or B. where there is no projected roster, the rosters for the three (3) months immediately preceding the leave excluding any period during which the Employee was not on the roster (for example, because of attendance at approved professional development or another form of paid leave).</p><p><strong>59.7</strong> Excess Annual leave Notwithstanding subclause 59.3 above, the Employer may, upon the provision of 10 weeks’ notice, direct the Employee to take up to one quarter of the Employee’s accrued annual leave entitlement, provided that the Employee has in excess of 304 hours’ annual leave accrued (pro rata for part-time Employees).</p><p><strong>59.8</strong> Employee not taken to be on paid annual leave at certain times</p><p><strong>(a)</strong> Public Holidays See also <a href="/eba/ebas/allied-health/leave/58-public-holidays.html">clause 58</a> (Public Holidays).</p><p>If an Employee takes paid annual leave during a period that includes a public holiday, the Employee is taken not to be on paid annual leave on that day and annual leave will not be deducted from an Employee’s accrual for that day.</p><p><strong>(b)</strong> Other Periods of Leave See also <a href="/eba/ebas/allied-health/leave/62-personal-leave-including-carer-s-leave.html">clause 62</a> (Personal Leave (including Carers Leave)) and 67 Compassionate Leave)</p><p><strong>(i)</strong> An Employee may take other types of leave, such as personal leave or compassionate leave whilst on annual leave. An Employee is taken not to be on paid annual leave whilst on other leave and the Employee’s paid annual leave accrual will be amended to reflect this. That is, annual leave will not be deducted from an Employee’s annual leave accrual for the time the Employee is on the other leave. These provisions do not apply to unpaid parental leave.</p><p><strong>(ii)</strong> An Employee taking personal leave whilst on annual leave will provide the Employer with evidence in accordance with <a href="/eba/ebas/allied-health/leave/62-personal-leave-including-carer-s-leave.html">clause 62</a> (Personal Leave (including Carers Leave)).</p><p><strong>(iii)</strong> An Employee taking compassionate leave whilst on annual leave will provide the Employer with evidence in accordance with <a href="/eba/ebas/allied-health/leave/67-compassionate-leave.html">clause 67</a> (Compassionate Leave).</p><p><strong>(iv)</strong> Where an Employee takes other leave during annual leave, any annual leave loading received for a period that is no longer annual leave is taken to have been paid in advance as required in subclause 59.6 (Payment for Leave). Where the Employee’s employment with the Employer ends prior to the Employee taking the annual leave for the period for which the Employee has been paid an amount as annual leave loading in advance, that amount is not payable under subclause 59.5 (Payment on termination).</p><p>Plain language terms: holidays, vacation.</p>',48)])])}const c=a(l,[["render",r]]);export{m as __pageData,c as default};
